import { Component, h, Host, Method, Prop, State } from '@stencil/core';
import { generateRandId } from '../../../utils/utils';

@Component({
  tag: 'wdpr-dual-combobox-group',
  styleUrl: 'wdpr-dual-combobox-group.css',
  scoped: true,
})
export class WdprDualComboboxGroup {
  private _internalId: string;

  @State() _hideGroup: boolean = false;

  @Prop() header: string;

  @Method()
  async hideGroup() {
    this._hideGroup = true;
  }

  @Method()
  async showGroup() {
    this._hideGroup = false;
  }

  componentWillLoad() {
    this._internalId = `wdpr-dual-combobox-group-${generateRandId()}`;
  }

  render() {
    return (
      <Host class={`${this._hideGroup ? 'hidden' : ''}`}>
        {this.header && (
          <span class="dual-combobox-header" id={`${this._internalId}-header`}>
            {this.header}
          </span>
        )}
        <div class="dual-combobox-group" role="group" aria-labelledby={this.header ? `${this._internalId}-header` : undefined}>
          <slot />
        </div>
      </Host>
    );
  }
}
